import{_ as o,o as r,c as t,a5 as s}from"./chunks/framework.DUVDhIjM.js";const a="/pr-preview/pr-191/diagrams/cross-consumption.svg",u=JSON.parse('{"title":"Cross-consumption","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/interaction-patterns/cross-consumption.md","filePath":"concepts/interaction-patterns/cross-consumption.md"}'),i={name:"concepts/interaction-patterns/cross-consumption.md"};function n(c,e,p,d,l,h){return r(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="cross-consumption" tabindex="-1">Cross-consumption <a class="header-anchor" href="#cross-consumption" aria-label="Permalink to &quot;Cross-consumption&quot;">​</a></h1><p>Cross-consumption describes teams composing services across provider boundaries. It is not a separate peer-to-peer consumer model; it is a way to describe how multiple provider APIs can be consumed together in one platform experience.</p><p>Use this pattern when a workload, team, or provider offering depends on capabilities from more than one provider.</p><h2 id="participating-personas" tabindex="-1">Participating personas <a class="header-anchor" href="#participating-personas" aria-label="Permalink to &quot;Participating personas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Persona</th><th>Role in the pattern</th></tr></thead><tbody><tr><td>Platform owner</td><td>Ensures account, identity, authorization, and discovery rules allow safe cross-provider consumption.</td></tr><tr><td>Service providers</td><td>Publish independent APIs that can be consumed together.</td></tr><tr><td>Service consumer</td><td>Selects and composes multiple provider APIs into an application or service workflow.</td></tr></tbody></table><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>Platform Mesh gives consumers a consistent way to discover and consume APIs from multiple providers. Each provider remains responsible for its own API and runtime. Consumers compose those APIs by creating desired-state resources in their account workspace or through higher-level platform workflows.</p><p><img src="'+a+'" alt="Cross consumption diagram"></p><p>Cross-consumption can also appear inside provider-to-provider relationships. A provider may consume several upstream providers to create a new offering, while still exposing a clean API to its own consumers.</p><h2 id="ownership-boundaries" tabindex="-1">Ownership boundaries <a class="header-anchor" href="#ownership-boundaries" aria-label="Permalink to &quot;Ownership boundaries&quot;">​</a></h2><p>The consumer owns the composition of requested capabilities. Each provider owns fulfillment for its own API. Platform Mesh owns the shared mediation layer that keeps discovery, authorization, account isolation, and API binding consistent across providers.</p><p>This avoids forcing every provider to directly integrate with every other provider, and avoids giving consumers direct access to provider runtimes.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./provider-to-consumer.html">Provider to consumer</a></li><li><a href="./provider-to-provider.html">Provider to provider</a></li><li><a href="./../personas/">Personas</a></li><li><a href="./../account-model.html">Account model</a></li></ul>',14)])])}const v=o(i,[["render",n]]);export{u as __pageData,v as default};
